-- ============================================================\n-- CUSTOMER PORTAL — Migration 08: Core Customer Profiles & Branches\n-- ============================================================\n\n-- Customer profiles\nCREATE TABLE IF NOT EXISTS public.customer_profiles (\n  id BIGINT GENERATED BY DEFAULT AS IDENTITY PRIMARY KEY,\n  portal_user_id UUID REFERENCES auth.users(id) ON DELETE CASCADE UNIQUE,\n  company_name TEXT NOT NULL,\n  tax_number TEXT,\n  commercial_register TEXT,\n  contact_email TEXT,\n  contact_phone TEXT,\n  website TEXT,\n  logo_url TEXT,\n  is_verified BOOLEAN DEFAULT FALSE,\n  created_at TIMESTAMP WITH TIME ZONE DEFAULT NOW(),\n  updated_at TIMESTAMP WITH TIME ZONE DEFAULT NOW()\n);\n\n-- Customer branches\nCREATE TABLE IF NOT EXISTS public.customer_branches (\n  id BIGINT GENERATED BY DEFAULT AS IDENTITY PRIMARY KEY,\n  customer_id BIGINT REFERENCES public.customer_profiles(id) ON DELETE CASCADE NOT NULL,\n  branch_name TEXT NOT NULL,\n  address TEXT NOT NULL,\n  city TEXT NOT NULL,\n  country TEXT DEFAULT 'Saudi Arabia',\n  is_primary BOOLEAN DEFAULT FALSE,\n  contact_phone TEXT,\n  created_at TIMESTAMP WITH TIME ZONE DEFAULT NOW()\n);\n\n-- Customer documents\nCREATE TABLE IF NOT EXISTS public.customer_documents (\n  id BIGINT GENERATED BY DEFAULT AS IDENTITY PRIMARY KEY,\n  customer_id BIGINT REFERENCES public.customer_profiles(id) ON DELETE CASCADE NOT NULL,\n  document_type TEXT NOT NULL CHECK (document_type IN ('CommercialRegistration','TaxCertificate','License','Other')),\n  document_name TEXT NOT NULL,\n  file_url TEXT NOT NULL,\n  expiry_date DATE,\n  is_verified BOOLEAN DEFAULT FALSE,\n  verified_by UUID REFERENCES auth.users(id) ON DELETE SET NULL,\n  verified_at TIMESTAMP WITH TIME ZONE,\n  created_at TIMESTAMP WITH TIME ZONE DEFAULT NOW()\n);\n\n-- Customer devices/sessions for security\nCREATE TABLE IF NOT EXISTS public.customer_devices (\n  id BIGINT GENERATED BY DEFAULT AS IDENTITY PRIMARY KEY,\n  portal_user_id UUID REFERENCES auth.users(id) ON DELETE CASCADE NOT NULL,\n  device_name TEXT,\n  ip_address TEXT,\n  user_agent TEXT,\n  last_active TIMESTAMP WITH TIME ZONE DEFAULT NOW(),\n  created_at TIMESTAMP WITH TIME ZONE DEFAULT NOW()\n);\n\n-- Enable RLS\nALTER TABLE public.customer_profiles ENABLE ROW LEVEL SECURITY;\nALTER TABLE public.customer_branches ENABLE ROW LEVEL SECURITY;\nALTER TABLE public.customer_documents ENABLE ROW LEVEL SECURITY;\nALTER TABLE public.customer_devices ENABLE ROW LEVEL SECURITY;\n\n-- Policies\nCREATE POLICY IF NOT EXISTS \"Customers view their own profile\"\n  ON public.customer_profiles FOR SELECT\n  USING (portal_user_id = auth.uid());\n\nCREATE POLICY IF NOT EXISTS \"Customers update their own profile\"\n  ON public.customer_profiles FOR UPDATE\n  USING (portal_user_id = auth.uid());\n\nCREATE POLICY IF NOT EXISTS \"Customers manage their own branches\"\n  ON public.customer_branches FOR ALL\n  USING (EXISTS (\n    SELECT 1 FROM public.customer_profiles p\n    WHERE p.id = customer_branches.customer_id AND p.portal_user_id = auth.uid()\n  ));\n\nCREATE POLICY IF NOT EXISTS \"Customers manage their own documents\"\n  ON public.customer_documents FOR ALL\n  USING (EXISTS (\n    SELECT 1 FROM public.customer_profiles p\n    WHERE p.id = customer_documents.customer_id AND p.portal_user_id = auth.uid()\n  ));\n\nCREATE POLICY IF NOT EXISTS \"Customers view their own device sessions\"\n  ON public.customer_devices FOR SELECT\n  USING (portal_user_id = auth.uid());\n
